<?php
namespace App\Filament\Pages;use App\Models\PaymentProviderSecret;use App\Services\Finance\{PaymentProviderManager,PaymentProviderSecretService};use App\Settings\OperationsSettings;use Filament\Notifications\Notification;use Illuminate\Contracts\Support\Htmlable;
class PaymentProviderSettings extends AdminOsModulePage{public string $secretKey='client_id',$secretValue='',$forgetReason='',$providerKey='disabled',$environment='sandbox';public ?string $merchantSerialNumber=null,$returnUrl=null,$callbackUrl=null;protected static string|\BackedEnum|null $navigationIcon='heroicon-o-credit-card';protected static ?string $navigationLabel='Provider Settings';protected static string|\UnitEnum|null $navigationGroup='Finance';protected static ?int $navigationSort=30;protected string $view='filament.pages.payment-provider-settings';public function getModuleKey():string{return 'finance';}public function getHeading():string|Htmlable{return '';}public static function canAccess():bool{return auth()->user()?->can('admin.finance.manage')??false;}public function mount():void{$s=app(OperationsSettings::class);$this->providerKey=$s->payment_provider_key;$this->environment=$s->vipps_mobilepay_environment;$this->merchantSerialNumber=$s->vipps_mobilepay_merchant_serial_number;$this->returnUrl=$s->vipps_mobilepay_return_url;$this->callbackUrl=$s->vipps_mobilepay_callback_url;}public function saveSettings():void{$this->validate(['providerKey'=>'required|in:disabled,vipps_mobilepay_sandbox','environment'=>'required|in:sandbox','merchantSerialNumber'=>'nullable|regex:/^\d{4,10}$/','returnUrl'=>'nullable|url','callbackUrl'=>'nullable|url']);$s=app(OperationsSettings::class);$s->payment_provider_key=$this->providerKey;$s->vipps_mobilepay_environment=$this->environment;$s->vipps_mobilepay_merchant_serial_number=$this->merchantSerialNumber;$s->vipps_mobilepay_return_url=$this->returnUrl;$s->vipps_mobilepay_callback_url=$this->callbackUrl;$s->vipps_mobilepay_capture_mode='manual';$s->vipps_mobilepay_outbound_http_allowed=false;$s->save();Notification::make()->title('Settings saved. Outbound HTTP remains blocked.')->success()->send();}public function setSecret():void{$this->validate(['secretKey'=>'required|in:client_id,client_secret,subscription_key,webhook_secret','secretValue'=>'required|string|min:8|max:4096']);app(PaymentProviderSecretService::class)->setSecret('vipps_mobilepay','sandbox',$this->secretKey,$this->secretValue,auth()->user());$this->secretValue='';}public function forgetSecret():void{$this->validate(['forgetReason'=>'required|string|min:5|max:500']);app(PaymentProviderSecretService::class)->forgetSecret('vipps_mobilepay','sandbox',$this->secretKey,auth()->user());$this->forgetReason='';}public function getViewData():array{return ['status'=>app(PaymentProviderManager::class)->status(),'secrets'=>PaymentProviderSecret::where('provider','vipps_mobilepay')->where('environment','sandbox')->get()->keyBy('key_name'),'financeUrl'=>route('filament.admin.pages.finance-control'),'securityUrl'=>route('filament.admin.pages.system-security'),'webhookUrl'=>url('/api/payments/vipps-mobilepay/webhook')];}}